export default function ClubNews({ news, isLeader }) {
    return (
        <div>
            {news.length === 0 && <div>No news yet.</div>}
            {news.map(n => (
                <div key={n.id} className="card">
                    <h4>{n.title}</h4>
                    <p>{n.content}</p>
                    {isLeader && <button>Delete</button>}
                </div>
            ))}
        </div>
    );
}
